import yaml

with open('/usr/lib/node_modules/langfuse-cli/openapi.yml', 'r') as f:
    spec = yaml.safe_load(f)

def fix_nullable(obj):
    if isinstance(obj, dict):
        if 'nullable' in obj and 'type' not in obj:
            obj['type'] = 'string'
        for v in obj.values():
            fix_nullable(v)
    elif isinstance(obj, list):
        for item in obj:
            fix_nullable(item)

fix_nullable(spec)

with open('/usr/lib/node_modules/langfuse-cli/openapi.yml', 'w') as f:
    yaml.dump(spec, f, default_flow_style=False, allow_unicode=True, sort_keys=False)

print('Fixed spec file')
